const agg = $input.first()?.json ?? {};
const raw = Array.isArray(agg.products) ? agg.products : [];

// Flatten 1 level: products = [ [..], [..] ]  ->  [.., ..]
const flattened = raw.flat();

// Remove null/empty objects
const cleaned = flattened.filter(p =>
  p && typeof p === "object" && Object.keys(p).length > 0
);

// 1) No products
if (cleaned.length === 0) {
  return [{
    json: {
      FilterMeOut: true,
      FilterReason: "NoProducts",
    }
  }];
}

// 2) De-dupe by product_type_info.id
const seen = new Set();
const deduped = [];
let hadDuplicates = false;

for (const p of cleaned) {
  const key = p?.product_type_info?.id ?? JSON.stringify(p); // fallback just in case
  if (seen.has(key)) {
    hadDuplicates = true;
    continue;
  }
  seen.add(key);
  deduped.push(p);
}

// 3) Decide what to do next
if (deduped.length === 1) {
  // Exactly 1 => carry on, still ONE item
  return [{
    json: {
      FilterMeOut: false,
      FilterReason: "OK",
      HadDuplicates: hadDuplicates,
      ...deduped[0],
    }
  }];
}

// More than 1 real product remains => stop (so you don't loop multiple times)
return [{
  json: {
    FilterMeOut: true,
    FilterReason: "MultipleProducts",
    ProductCount: deduped.length,
    HadDuplicates: hadDuplicates,
    // optional debug
    ProductTypeIds: deduped.map(p => p.product_type_info?.id).filter(Boolean),
  }
}];

