// Select your timezone offset here
const TZ_OFFSET_HOURS = 8; // Perth = 8, Brisbane = 10, Sydney = 11 (DST), NZ = 13

// Helper to shift UTC time to target timezone
const shiftToTz = (date, offsetHours) => {
  const shifted = new Date(date.getTime() + offsetHours * 3600 * 1000);
  return shifted;
};

// Helper to format YYYY-MM-DD using shifted date
const formatLocal = (d) => {
  const year = d.getUTCFullYear();
  const month = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// Current UTC time
const nowUtc = new Date();

// Convert to local timezone
const todayLocal = shiftToTz(nowUtc, TZ_OFFSET_HOURS);

// Yesterday in local timezone
const yesterdayLocal = new Date(todayLocal.getTime() - 24 * 3600 * 1000);

// Output
return [
  {
    json: {
      start_date: formatLocal(yesterdayLocal),
      end_date: formatLocal(todayLocal),
    }
  }
];
